import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Memory {
  id: number;
  title: string;
  description: string;
  imageUrl: string;
  date: string;
}

export interface LoveReason {
  id: number;
  icon: string;
  text: string;
}

import { GoogleGenAI } from "@google/genai";

export const generateRomanticMessage = async (keywords: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Write a very romantic, short, and poetic love letter for Propose Day based on these keywords: ${keywords}. Make it emotional, heartfelt, and ending with a beautiful proposal-like sentiment. Keep it under 150 words.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });

    return response.text || "My love for you grows more every day. Words can't describe how much you mean to me.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Every moment with you is a dream come true. Will you stay by my side forever?";
  }
};

