interface MemoryGalleryProps {
  onNext: () => void;
}

const MemoryGallery: React.FC<MemoryGalleryProps> = ({ onNext }) => {
  const [currentIdx, setCurrentIdx] = useState(0);

  const next = () => setCurrentIdx((prev) => (prev + 1) % MEMORIES.length);
  const prev = () => setCurrentIdx((prev) => (prev - 1 + MEMORIES.length) % MEMORIES.length);

  return (
    <div className="w-full space-y-8 animate-in zoom-in-95 duration-700">
      <div className="text-center">
        <h3 className="text-4xl font-romantic text-rose-600 mb-2">Our Journey Together</h3>
        <p className="text-gray-500 italic">Every moment with you is a treasure</p>
      </div>

      <div className="relative group max-w-2xl mx-auto rounded-3xl overflow-hidden shadow-2xl border-4 border-white">
        <img 
          src={MEMORIES[currentIdx].img} 
          alt={MEMORIES[currentIdx].title}
          className="w-full h-[400px] object-cover transition-opacity duration-500"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent flex flex-col justify-end p-8 text-white">
          <span className="text-rose-400 font-bold text-sm tracking-widest uppercase">{MEMORIES[currentIdx].date}</span>
          <h4 className="text-3xl font-romantic font-bold">{MEMORIES[currentIdx].title}</h4>
          <p className="opacity-90">{MEMORIES[currentIdx].desc}</p>
        </div>

        <button 
          onClick={prev}
          className="absolute left-4 top-1/2 -translate-y-1/2 bg-white/20 hover:bg-white/40 backdrop-blur-md p-2 rounded-full transition"
        >
          <ChevronLeft className="text-white w-8 h-8" />
