import React, { useState } from 'react';
import { generateRomanticMessage } from '../services/geminiService';
import { Sparkles, Send, RefreshCw, Heart } from 'lucide-react';

interface LoveLetterGeneratorProps {
  onNext: () => void;
}

const LoveLetterGenerator: React.FC<LoveLetterGeneratorProps> = ({ onNext }) => {
  const [keywords, setKeywords] = useState('');
  const [poem, setPoem] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!keywords.trim()) return;
    setLoading(true);
    const result = await generateRomanticMessage(keywords);
    setPoem(result);
    setLoading(false);
  };

  return (
    <div className="w-full max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right-10 duration-700">
      <div className="text-center">
        <h3 className="text-4xl font-romantic text-rose-600 mb-2">A Message from the Soul</h3>
        <p className="text-gray-500 italic">I asked the stars to help me write how I feel...</p>
      </div>

      {!poem ? (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-rose-100 space-y-6">
          <div>
            <label className="block text-rose-600 font-bold mb-2">Think of 3-4 things that define "Us"</label>
            <input 
              type="text" 
              placeholder="e.g., laughter, sunset beach, coffee, kindness"
              className="w-full px-4 py-3 border-2 border-rose-100 rounded-xl focus:border-rose-300 focus:outline-none transition"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
            />
          </div>
          <button
            onClick={handleGenerate}
            disabled={loading}
            className="w-full py-4 bg-gradient-to-r from-rose-400 to-pink-500 text-white rounded-xl font-bold shadow-lg flex items-center justify-center gap-3 hover:shadow-xl transition disabled:opacity-50"
          >
            {loading ? <RefreshCw className="animate-spin" /> : <Sparkles />}
            {loading ? 'Crafting magic...' : 'Generate Our Love Poem'}
          </button>
        </div>
      ) : (
        <div className="bg-white p-10 rounded-3xl shadow-2xl border-2 border-rose-200 relative overflow-hidden">
          <Heart className="absolute -top-10 -right-10 w-40 h-40 text-rose-50 opacity-50 fill-rose-50" />
          <div className="relative z-10 space-y-6">
            <p className="text-2xl font-romantic text-rose-800 leading-relaxed italic whitespace-pre-line text-center">
              "{poem}"
            </p>
            <div className="flex flex-col gap-4">
               <button
                onClick={() => setPoem('')}
                className="text-rose-400 text-sm font-semibold flex items-center justify-center gap-2 hover:text-rose-600 transition"
              >
                <RefreshCw className="w-4 h-4" /> Try again with different words
              </button>
              <button
                onClick={onNext}
                className="w-full py-4 bg-rose-600 text-white rounded-xl font-bold shadow-lg hover:bg-rose-700 transition flex items-center justify-center gap-3"
              >
                Now, I have one final question... <Heart className="w-5 h-5 fill-white" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default LoveLetterGenerator;

import React, { useState, useEffect } from 'react';
import { Heart, Stars } from 'lucide-react';

const ProposalSection: React.FC = () => {
  const [noPos, setNoPos] = useState({ top: '0px', left: '0px' });
  const [isAccepted, setIsAccepted] = useState(false);
  const [isHoveringNo, setIsHoveringNo] = useState(false);

  const moveNoButton = () => {
    const randomTop = Math.floor(Math.random() * 200) - 100;
    const randomLeft = Math.floor(Math.random() * 200) - 100;
    setNoPos({ top: `${randomTop}px`, left: `${randomLeft}px` });
    setIsHoveringNo(true);
  };

  const handleYes = () => {
    setIsAccepted(true);
  };

  if (isAccepted) {
    return (
      <div className="text-center space-y-8 animate-in zoom-in duration-1000 py-12">
        <h2 className="text-6xl md:text-8xl font-fancy text-rose-600 animate-bounce">I Love You!</h2>
        <div className="relative inline-block">
          <div className="absolute inset-0 bg-pink-400 blur-3xl opacity-40 animate-pulse rounded-full"></div>
          <img src="https://picsum.photos/seed/happy/600/400" alt="Happiness" className="relative rounded-3xl shadow-2xl border-8 border-white w-full max-w-md mx-auto" />
        </div>
        <p className="text-3xl font-romantic text-rose-800">You've made me the happiest person alive.</p>
        <p className="text-xl text-gray-600 font-medium">Forever starts today. ❤️</p>
        <div className="flex justify-center gap-4">
          <Stars className="w-8 h-8 text-yellow-400 fill-yellow-400 animate-pulse" />
          <Heart className="w-8 h-8 text-rose-500 fill-rose-500 animate-pulse" />
          <Stars className="w-8 h-8 text-yellow-400 fill-yellow-400 animate-pulse" />
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-2xl mx-auto flex flex-col items-center text-center space-y-12 animate-in fade-in duration-1000 py-10">
      <div className="relative group">
        <Heart className="w-32 h-32 text-rose-500 fill-rose-500 group-hover:scale-110 transition duration-500" />
        <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-white font-bold text-xs uppercase tracking-tighter">LOVE</span>
        </div>
      </div>

      <div className="space-y-4">
        <h2 className="text-5xl md:text-7xl font-romantic text-rose-600">Will you be mine?</h2>
        <p className="text-xl text-gray-600 italic">Every day, every night, forever...</p>
      </div>

      <div className="flex flex-col md:flex-row gap-8 items-center justify-center w-full">
        <button
          onClick={handleYes}
          className="order-1 md:order-none px-16 py-5 bg-rose-600 text-white rounded-full text-2xl font-bold shadow-2xl hover:bg-rose-700 hover:scale-110 transition-all active:scale-95 z-20"
        >
          YES!
        </button>

        <button
          onMouseEnter={moveNoButton}
          onClick={moveNoButton}
          style={{ 
            position: 'relative',
            top: noPos.top,
            left: noPos.left,
            transition: 'all 0.2s ease-out'
          }}
          className="px-8 py-3 bg-gray-200 text-gray-500 rounded-full font-bold shadow-md opacity-80 cursor-default"
        >
          {isHoveringNo ? 'Try again! 😉' : 'No'}
        </button>
      </div>

      {isHoveringNo && (
        <p className="text-rose-400 animate-pulse font-medium">There is no "No" in our story! ❤️</p>
      )}
    </div>
  );
};

export default ProposalSection;

