import React, { useState } from 'react';
import { generateRomanticMessage } from '../services/geminiService';
import { Sparkles, Send, RefreshCw, Heart } from 'lucide-react';

interface LoveLetterGeneratorProps {
  onNext: () => void;
}

const LoveLetterGenerator: React.FC<LoveLetterGeneratorProps> = ({ onNext }) => {
  const [keywords, setKeywords] = useState('');
  const [poem, setPoem] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!keywords.trim()) return;
    setLoading(true);
    const result = await generateRomanticMessage(keywords);
    setPoem(result);
    setLoading(false);
  };

  return (
    <div className="w-full max-w-2xl mx-auto space-y-8 animate-in slide-in-from-right-10 duration-700">
      <div className="text-center">
        <h3 className="text-5xl font-romantic text-rose-600 mb-2 font-semibold">A Message from the Soul</h3>
        <p className="text-gray-500 italic">I asked the stars to help me write how I feel...</p>
      </div>

      {!poem ? (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-rose-100 space-y-6">
          <div>
            <label className="block text-rose-600 font-bold mb-2">Think of 3-4 things that define "Us"</label>
            <input 
              type="text" 
              placeholder="e.g., laughter, sunset beach, coffee, kindness"
              className="w-full px-4 py-3 border-2 border-rose-100 rounded-xl focus:border-rose-300 focus:outline-none transition"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
            />
          </div>
          <button
            onClick={handleGenerate}
            disabled={loading}
            className="w-full py-4 bg-gradient-to-r from-rose-400 to-pink-500 text-white rounded-xl font-bold shadow-lg flex items-center justify-center gap-3 hover:shadow-xl transition disabled:opacity-50"
          >
            {loading ? <RefreshCw className="animate-spin" /> : <Sparkles />}
            {loading ? 'Crafting magic...' : 'Generate Our Love Poem'}
          </button>
        </div>
      ) : (
        <div className="bg-white p-10 rounded-3xl shadow-2xl border-2 border-rose-200 relative overflow-hidden">
          <Heart className="absolute -top-10 -right-10 w-40 h-40 text-rose-50 opacity-50 fill-rose-50" />
          <div className="relative z-10 space-y-8">
            <p className="text-3xl md:text-4xl font-romantic text-rose-800 leading-relaxed italic whitespace-pre-line text-center font-medium">
              "{poem}"
            </p>
            <div className="flex flex-col gap-4">
               <button
                onClick={() => setPoem('')}
                className="text-rose-400 text-sm font-semibold flex items-center justify-center gap-2 hover:text-rose-600 transition"
              >
                <RefreshCw className="w-4 h-4" /> Try again with different words
              </button>
              <button
                onClick={onNext}
                className="w-full py-4 bg-rose-600 text-white rounded-xl font-bold shadow-lg hover:bg-rose-700 transition flex items-center justify-center gap-3"
              >
                Now, I have one final question... <Heart className="w-5 h-5 fill-white" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

