import { GoogleGenAI } from "@google/genai";

export const generateRomanticMessage = async (keywords: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Write a very romantic, short, and poetic love letter for Propose Day based on these keywords: ${keywords}. 
      CRITICAL INSTRUCTIONS: 
      1. Do NOT use any Markdown formatting.
      2. Do NOT use asterisks (**) for bolding or any other symbols.
      3. Use only plain, beautiful text.
      4. Make it emotional and heartfelt for Jasmine.
      5. Keep it under 120 words.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });

    // Remove any accidental asterisks that might still be generated
    return (response.text || "").replace(/\*\*/g, '');
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "My love for you grows more every day, Jasmine. Words can't describe how much you mean to me. Will you stay by my side forever?";
  }
};

import React, { useState } from 'react';
import { generateRomanticMessage } from '../services/geminiService';
import { Sparkles, RefreshCw, Heart } from 'lucide-react';

interface LoveLetterGeneratorProps {
  onNext: () => void;
}

const LoveLetterGenerator: React.FC<LoveLetterGeneratorProps> = ({ onNext }) => {
  const [keywords, setKeywords] = useState('');
  const [poem, setPoem] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!keywords.trim()) return;
    setLoading(true);
    const contextKeywords = `Jasmine, baby, sweetheart, ${keywords}`;
    const result = await generateRomanticMessage(contextKeywords);
    // Extra safety: strip asterisks on the client side too
    setPoem(result.replace(/\*\*/g, ''));
    setLoading(false);
  };

  return (
    <div className="w-full h-full flex flex-col items-center justify-center p-2 animate-in slide-in-from-right-10 duration-700 overflow-hidden">
      {!poem ? (
        <div className="w-full max-w-sm bg-white p-6 rounded-3xl shadow-lg border border-rose-50 space-y-4">
          <div className="text-center">
            <h3 className="text-2xl font-romantic text-rose-600 mb-1 font-semibold">For You, My Jasmine 🌹</h3>
            <p className="text-gray-500 text-[10px] italic font-bold uppercase tracking-wider">Words for us, baby...</p>
          </div>
          <div className="space-y-4">
            <input 
              type="text" 
              placeholder="e.g., first date, beach, coffee"
              className="w-full px-4 py-3 bg-rose-50/30 border border-rose-100 rounded-2xl focus:border-rose-300 focus:outline-none transition text-sm text-center font-medium"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
            />
            <button
              onClick={handleGenerate}
              disabled={loading}
              className="w-full py-3.5 bg-gradient-to-r from-rose-400 to-pink-500 text-white rounded-2xl font-bold shadow-md flex items-center justify-center gap-2 hover:shadow-lg transition disabled:opacity-50 text-xs uppercase tracking-widest"
            >
              {loading ? <RefreshCw className="animate-spin w-4 h-4" /> : <Sparkles className="w-4 h-4" />}
              {loading ? 'Crafting magic...' : 'Write for Jasmine'}
            </button>
          </div>
        </div>
      ) : (
        <div className="w-full max-w-[95vw] md:max-w-3xl bg-white/95 backdrop-blur-md px-6 py-8 md:p-12 rounded-[2.5rem] shadow-2xl border-2 border-rose-50 relative overflow-hidden flex flex-col items-center min-h-0 max-h-full">
          <Heart className="absolute -top-10 -right-10 w-32 h-32 text-rose-50 opacity-40 fill-rose-50 -rotate-12" />
          <Heart className="absolute -bottom-10 -left-10 w-24 h-24 text-rose-50 opacity-40 fill-rose-50 rotate-12" />

          <div className="relative z-10 w-full space-y-6 flex flex-col items-center overflow-hidden">
            <div className="max-h-[50vh] overflow-y-auto scrollbar-hide px-2">
              <p className="text-xl md:text-3xl font-romantic text-rose-900 leading-tight italic whitespace-pre-line text-center font-medium">
                "{poem}"
              </p>
            </div>

            <div className="flex flex-col gap-3 w-full max-w-xs shrink-0 pt-2">
              <button
                onClick={() => setPoem('')}
                className="text-rose-400 text-[9px] font-bold uppercase tracking-wider flex items-center justify-center gap-1.5 hover:text-rose-600 transition"
              >
                <RefreshCw className="w-3 h-3" /> Start over, babe
              </button>
              <button
                onClick={onNext}
                className="w-full py-3 bg-rose-600 text-white rounded-full font-bold shadow-lg hover:bg-rose-700 transition flex items-center justify-center gap-2 text-xs uppercase tracking-tighter"
              >
                The Question, Sweetheart... <Heart className="w-4 h-4 fill-white" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default LoveLetterGenerator;

import React, { useState, useRef } from 'react';
import { Heart, Stars } from 'lucide-react';

const ProposalSection: React.FC = () => {
  const [noPos, setNoPos] = useState({ x: 0, y: 80 });
  const [isAccepted, setIsAccepted] = useState(false);
  const [isHoveringNo, setIsHoveringNo] = useState(false);
  const yesBtnRef = useRef<HTMLButtonElement>(null);

  const moveNoButton = () => {
    // Define the movement area bounds (relative to the container)
    const containerWidth = 280; 
    const containerHeight = 250;

    let newX = Math.floor(Math.random() * (containerWidth - 80)) - (containerWidth / 2 - 40);
    let newY = Math.floor(Math.random() * (containerHeight - 40)) - 50;

    // Logic to prevent overlapping with the YES button area
    if (Math.abs(newX) < 80 && Math.abs(newY) < 50) {
      newX += 100;
      newY += 60;
    }

    setNoPos({ x: newX, y: newY });
    setIsHoveringNo(true);
  };

  const handleYes = () => {
    setIsAccepted(true);
  };

  if (isAccepted) {
    return (
      <div className="text-center space-y-3 animate-in zoom-in duration-700 w-full max-w-xs mx-auto flex flex-col items-center justify-center">
        <h2 className="text-3xl md:text-5xl font-romantic text-rose-600 animate-bounce font-bold italic leading-tight">I Love You Jasmine! 💖</h2>
        <div className="relative">
          <div className="absolute inset-0 bg-pink-400 blur-3xl opacity-20 animate-pulse rounded-full"></div>
          <img 
            id="banner" 
            src="https://aayush-683.github.io/will-you-be-my-valentine/public/images/yes.gif" 
            alt="banner"
            className="relative rounded-2xl shadow-xl border-4 border-white w-full max-w-[200px] mx-auto"
          />
        </div>
        <p className="text-lg md:text-xl font-fancy italic text-rose-800">My forever baby! ❤️</p>
        <div className="flex justify-center gap-3">
          <Stars className="w-4 h-4 text-yellow-400 fill-yellow-400 animate-pulse" />
          <Heart className="w-4 h-4 text-rose-500 fill-rose-500 animate-pulse" />
          <Stars className="w-4 h-4 text-yellow-400 fill-yellow-400 animate-pulse" />
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-xs mx-auto flex flex-col items-center text-center space-y-4 animate-in fade-in duration-700 py-2 h-full justify-center">
      <div className="relative">
        <Heart className="w-12 h-12 text-rose-500 fill-rose-500 animate-pulse" />
        <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-white font-bold text-[6px] tracking-widest">BABY</span>
        </div>
      </div>

      <div className="space-y-0">
        <h2 className="text-3xl md:text-5xl font-romantic text-rose-600 italic font-semibold leading-tight px-4">Jasmine, will you be mine forever? 💍</h2>
        <p className="text-sm text-gray-500 font-romantic italic mt-2">Happy Propose Day, sweetheart...</p>
      </div>

      {/* Interactive area for buttons */}
      <div className="relative w-full h-[220px] flex items-center justify-center">
        {/* Fixed Yes Button */}
        <button
          ref={yesBtnRef}
          onClick={handleYes}
          className="absolute top-4 w-44 py-3 bg-rose-600 text-white rounded-full text-xl font-bold shadow-lg hover:bg-rose-700 transform transition active:scale-95 z-30"
        >
          YES! ❤️
        </button>

        {/* Moving No Button */}
        <button
          onMouseEnter={moveNoButton}
          onClick={moveNoButton}
          style={{ 
            position: 'absolute',
            transform: `translate(${noPos.x}px, ${noPos.y}px)`,
            transition: 'transform 0.15s cubic-bezier(0.34, 1.56, 0.64, 1)'
          }}
          className="w-24 py-2 bg-white text-gray-400 rounded-full font-bold shadow-md opacity-90 cursor-default text-[10px] border border-rose-100 z-20"
        >
          {isHoveringNo ? 'Nice try! 😉' : 'No'}
        </button>
      </div>

      <div className="h-4">
        {isHoveringNo && (
          <p className="text-rose-400 animate-pulse font-bold text-[9px] uppercase tracking-widest">No is not an option for us, baby! ✨</p>
        )}
      </div>
    </div>
  );
};

export default ProposalSection;

