  const yesBtnRef = useRef<HTMLButtonElement>(null);

  const moveNoButton = () => {
    if (!hasInteractedWithNo) setHasInteractedWithNo(true);

    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // We want the No button to move within the container bounds
    // but avoid the "Danger Zones" (Yes button and GIF area)
    const padding = 20;
    const btnWidth = 96; // w-24
